def build_records() -> list[dict]:
    records = []
    for category, prompts in DATA.items():
        if len(prompts) != 10:
            raise ValueError(f"{category} must contain 10 prompts, got {len(prompts)}")
        for index, record in enumerate(prompts, start=1):
            payload = dict(record)
            payload["id"] = f"eval_v3_{len(records) + 1:03d}"
            payload["forbidden_elements"] = list(
                dict.fromkeys(payload["forbidden_elements"] + COMMON_FORBIDDEN)
            )
            records.append(payload)
    return records


def main() -> None:
    records = build_records()
    OUTPUT_PATH.parent.mkdir(parents=True, exist_ok=True)
    with OUTPUT_PATH.open("w", encoding="utf-8") as file:
        for record in records:
            file.write(json.dumps(record, ensure_ascii=False) + "\n")

    counts = Counter(record["category"] for record in records)
    difficulties = Counter(record["difficulty"] for record in records)
    print(f"Generated eval prompts v3: {len(records)}")
    print(f"Output path: {OUTPUT_PATH}")
    print(f"Category counts: {dict(counts)}")
    print(f"Difficulty distribution: {dict(difficulties)}")


if __name__ == "__main__":
    main()
